@Override
    public Object apply(Object o) {
        if (o == null || o instanceof BigDecimal) {
            return o;
        }

        if (o instanceof Boolean) {
            return (Boolean) o ? BigDecimal.ONE : BigDecimal.ZERO;
        }

        if (o instanceof Byte
                || o instanceof Short
                || o instanceof Integer
                || o instanceof Long
                || o instanceof AtomicInteger
                || o instanceof AtomicLong
        ) {
            return BigDecimal.valueOf(((Number) o).longValue());
        }

        if (o instanceof Float || o instanceof Double) {
            double doubleValue = ((Number) o).doubleValue();
            return toBigDecimal(doubleValue);
        }

        if (o instanceof BigInteger) {
            return new BigDecimal((BigInteger) o);
        }

        if (o instanceof String) {
            return new BigDecimal((String) o);
        }

        throw new JSONException("can not cast to BigDecimal " + o.getClass());
    }

public void putUTF8(final String stringValue) {
    int charLength = stringValue.length();
    if (charLength > 65535) {
        throw new IllegalArgumentException("UTF8 string too large");
    }
    int currentLength = length;
    if (currentLength + 2 + charLength > data.length) {
        enlarge(2 + charLength);
    }
    byte[] currentData = data;
    // Optimistic algorithm: instead of computing the byte length and then serializing the string
    // (which requires two loops), we assume the byte length is equal to char length (which is the
    // most frequent case), and we start serializing the string right away. During the
    // serialization, if we find that this assumption is wrong, we continue with the general method.
    currentData[currentLength++] = (byte) (charLength >>> 8);
    currentData[currentLength++] = (byte) charLength;
    for (int i = 0; i < charLength; ++i) {
        char charValue = stringValue.charAt(i);
        if (charValue >= '\u0001' && charValue <= '\u007F') {
            currentData[currentLength++] = (byte) charValue;
        } else {
            length = currentLength;
            encodeUtf8(stringValue, i);
            return;
        }
    }
    length = currentLength;
}

final void setInputFrameFromDescriptor(
        final SymbolTable symbolTable,
        final int access,
        final String descriptor,
        final int maxLocals) {
    inputLocals = new int[maxLocals];
    inputStack = new int[0];
    int inputLocalIndex = 0;
    if ((access & Opcodes.ACC_STATIC) == 0) {
        if ((access & Constants.ACC_CONSTRUCTOR) == 0) {
            inputLocals[inputLocalIndex++] =
                    REFERENCE_KIND | symbolTable.addType(symbolTable.className);
        } else {
            inputLocals[inputLocalIndex++] = UNINITIALIZED_THIS;
        }
    }
    for (Type argumentType : Type.getArgumentTypes(descriptor)) {
        int abstractType =
                getAbstractTypeFromDescriptor(symbolTable, argumentType.getDescriptor(), 0);
        inputLocals[inputLocalIndex++] = abstractType;
        if (abstractType == LONG || abstractType == DOUBLE) {
            inputLocals[inputLocalIndex++] = TOP;
        }
    }
    while (inputLocalIndex < maxLocals) {
        inputLocals[inputLocalIndex++] = TOP;
    }
}

public String getClassName() {
    switch (sort) {
        case VOID:
            return "void";
        case BOOLEAN:
            return "boolean";
        case CHAR:
            return "char";
        case BYTE:
            return "byte";
        case SHORT:
            return "short";
        case INT:
            return "int";
        case FLOAT:
            return "float";
        case LONG:
            return "long";
        case DOUBLE:
            return "double";
        case ARRAY:
            Type elementType = getTypeInternal(valueBuffer, valueBegin + getDimensions(), valueEnd);
            StringBuilder stringBuilder = new StringBuilder(elementType.getClassName());
            for (int i = getDimensions(); i > 0; --i) {
                stringBuilder.append("[]");
            }
            return stringBuilder.toString();
        case OBJECT:
        case INTERNAL:
            return valueBuffer.substring(valueBegin, valueEnd).replace('/', '.');
        default:
            throw new AssertionError();
    }
}

@SuppressWarnings("unchecked")
    static <T> T parseObject(
            String text,
            Class<T> clazz,
            Filter filter,
            JSONReader.Feature... features
    ) {
        if (text == null || text.isEmpty()) {
            return null;
        }

        final JSONReader.Context context = JSONFactory.createReadContext(filter, features);
        boolean fieldBased = (context.features & JSONReader.Feature.FieldBased.mask) != 0;
        ObjectReader<T> objectReader = context.provider.getObjectReader(clazz, fieldBased);

        try (JSONReader reader = JSONReader.of(text, context)) {
            if (reader.nextIfNull()) {
                return null;
            }

            T object = objectReader.readObject(reader, clazz, null, 0);
            if (reader.resolveTasks != null) {
                reader.handleResolveTasks(object);
            }
            if (reader.ch != EOI && (context.features & IgnoreCheckClose.mask) == 0) {
                throw new JSONException(reader.info("input not end"));
            }
            return object;
        }
    }

@SuppressWarnings("unchecked")
    static <T> T parseObject(
            String text,
            Type type,
            String format,
            Filter[] filters,
            JSONReader.Feature... features
    ) {
        if (text == null || text.isEmpty()) {
            return null;
        }

        JSONReader.Context context = new JSONReader.Context(
                JSONFactory.getDefaultObjectReaderProvider(),
                null,
                filters,
                features
        );
        context.setDateFormat(format);

        boolean fieldBased = (context.features & JSONReader.Feature.FieldBased.mask) != 0;
        ObjectReader<T> objectReader = context.provider.getObjectReader(type, fieldBased);

        try (JSONReader reader = JSONReader.of(text, context)) {
            if (reader.nextIfNull()) {
                return null;
            }

            T object = objectReader.readObject(reader, type, null, 0);
            if (reader.resolveTasks != null) {
                reader.handleResolveTasks(object);
            }
            if (reader.ch != EOI && (context.features & IgnoreCheckClose.mask) == 0) {
                throw new JSONException(reader.info("input not end"));
            }
            return object;
        }
    }

static <T> List<T> parseArray(String text, Type[] types, JSONReader.Feature... features) {
    if (text == null || text.isEmpty()) {
        return null;
    }

    final JSONReader.Context context = JSONFactory.createReadContext(features);
    try (JSONReader reader = JSONReader.of(text, context)) {
        if (reader.nextIfNull()) {
            return null;
        }

        reader.startArray();
        List<T> array = new ArrayList<>(types.length);
        for (int i = 0; i < types.length; i++) {
            array.add(
                    reader.read(types[i])
            );
        }
        reader.endArray();
        if (reader.resolveTasks != null) {
            reader.handleResolveTasks(array);
        }
        if (reader.ch != EOI && (context.features & IgnoreCheckClose.mask) == 0) {
            throw new JSONException(reader.info("input not end"));
        }
        return array;
    }
}

@SuppressWarnings({"unchecked", "rawtypes"})
    public JSONObject getJSONObject(int index) {
        Object value = get(index);

        if (value == null) {
            return null;
        }

        if (value instanceof JSONObject) {
            return (JSONObject) value;
        }

        if (value instanceof String) {
            String str = (String) value;

            if (str.isEmpty() || "null".equalsIgnoreCase(str)) {
                return null;
            }

            JSONReader reader = JSONReader.of(str);
            return JSONFactory.OBJECT_READER.readObject(reader, null, null, 0);
        }

        if (value instanceof Map) {
            JSONObject object = new JSONObject((Map) value);
            set(index, object);
            return object;
        }

        Class valueClass = value.getClass();
        ObjectWriter objectWriter = JSONFactory.getDefaultObjectWriterProvider().getObjectWriter(valueClass);

        JSONObject jsonObject = (objectWriter instanceof ObjectWriterAdapter)
                ? ((ObjectWriterAdapter) objectWriter).toJSONObject(value)
                : (JSONObject) JSON.toJSON(value);

        set(index, jsonObject);
        return jsonObject;
    }

static <T> T parseObject(byte[] jsonbBytes, Class<T> objectClass, JSONReader.Context context) {
    try (JSONReaderJSONB jsonReader = new JSONReaderJSONB(
            context,
            jsonbBytes,
            0,
            jsonbBytes.length)
    ) {
        Object object;
        if (objectClass == Object.class) {
            object = jsonReader.readAnyObject();
        } else {
            ObjectReader objectReader = context.provider.getObjectReader(
                    objectClass,
                    (context.features & JSONReader.Feature.FieldBased.mask) != 0
            );
            if ((context.features & JSONReader.Feature.SupportArrayToBean.mask) != 0
                    && jsonReader.isArray()
                    && objectReader instanceof ObjectReaderBean
            ) {
                object = objectReader.readArrayMappingJSONBObject(jsonReader, objectClass, null, 0);
            } else {
                object = objectReader.readJSONBObject(jsonReader, objectClass, null, 0);
            }
        }

        if (jsonReader.resolveTasks != null) {
            jsonReader.handleResolveTasks(object);
        }
        return (T) object;
    }
}

