@Override
    public Object extract(JSONReader jsonReader) {
        if (jsonReader == null) {
            return null;
        }

        if (!extractSupport) {
            Object root = jsonReader.readAny();
            return eval(root);
        }

        Context context0 = new Context(this, null, first, second, 0);
        first.accept(jsonReader, context0);

        Context context1 = new Context(this, context0, second, null, 0);

        if (context0.eval) {
            second.eval(context1);
        } else {
            second.accept(jsonReader, context1);
        }

        Object contextValue = context1.value;

        if ((features & Feature.AlwaysReturnList.mask) != 0) {
            if (contextValue == null) {
                contextValue = new JSONArray();
            } else if (!(contextValue instanceof List)) {
                contextValue = JSONArray.of(contextValue);
            }
        }

        if (contextValue instanceof Sequence) {
            contextValue = ((Sequence) contextValue).values;
        }

        return contextValue;
    }

JSONPathTypedMultiIndexes(
        JSONPath[] paths,
        JSONPath prefix,
        JSONPath[] indexPaths,
        Type[] types,
        String[] formats,
        long[] pathFeatures,
        ZoneId zoneId,
        long features
) {
    super(paths, types, formats, pathFeatures, zoneId, features);
    this.prefix = prefix;
    this.indexPaths = indexPaths;
    int[] indexes = new int[paths.length];
    for (int i = 0; i < indexPaths.length; i++) {
        JSONPathSingleIndex indexPath = (JSONPathSingleIndex) indexPaths[i];
        indexes[i] = indexPath.index;
    }
    this.indexes = indexes;

    boolean duplicate = false;
    int maxIndex = -1;
    for (int i = 0; i < indexes.length; i++) {
        int index = indexes[i];
        if (i == 0) {
            maxIndex = index;
        } else {
            maxIndex = Math.max(maxIndex, index);
        }

        for (int j = 0; j < indexes.length && !duplicate; j++) {
            if (j != i && index == indexes[j]) {
                duplicate = true;
                break;
            }
        }
    }
    this.duplicate = duplicate;
    this.maxIndex = maxIndex;
}

@Override
    public Object extract(JSONReader jsonReader) {
        if (jsonReader.nextIfNull()) {
            return new Object[paths.length];
        }

        if (!jsonReader.nextIfArrayStart()) {
            throw new JSONException(jsonReader.info("illegal input, expect '[', but " + jsonReader.current()));
        }

        for (int i = 0; i < index; ++i) {
            if (jsonReader.nextIfArrayEnd()) {
                return new Object[paths.length];
            }

            if (jsonReader.isEnd()) {
                throw new JSONException(jsonReader.info("illegal input, expect '[', but " + jsonReader.current()));
            }

            jsonReader.skipValue();
        }

        if (jsonReader.nextIfNull()) {
            return new Object[paths.length];
        }

        if (jsonReader.nextIfArrayEnd()) {
            return new Object[paths.length];
        }

        return objectReader.readObject(jsonReader);
    }

@Override
    public Object extract(JSONReader jsonReader) {
        if (jsonReader.nextIfNull()) {
            return new Object[paths.length];
        }

        if (!jsonReader.nextIfObjectStart()) {
            throw new JSONException(jsonReader.info("illegal input, expect '[', but " + jsonReader.current()));
        }

        while (true) {
            if (jsonReader.nextIfObjectEnd()) {
                return new Object[paths.length];
            }

            if (jsonReader.isEnd()) {
                throw new JSONException(jsonReader.info("illegal input, expect '[', but " + jsonReader.current()));
            }

            long nameHashCode = jsonReader.readFieldNameHashCode();
            boolean match = nameHashCode == prefixNameHash;
            if (!match) {
                jsonReader.skipValue();
                continue;
            }

            break;
        }

        if (jsonReader.nextIfNull()) {
            return new Object[paths.length];
        }

        if (!jsonReader.nextIfObjectStart()) {
            throw new JSONException(jsonReader.info("illegal input, expect '[', but " + jsonReader.current()));
        }

        return objectReader.readObject(jsonReader);
    }

public final boolean isWriteTypeInfo(Object object, Type fieldType) {
    long features = context.features;
    if ((features & WriteClassName.mask) == 0
            || object == null
    ) {
        return false;
    }

    Class objectClass = object.getClass();
    Class fieldClass = null;
    if (fieldType instanceof Class) {
        fieldClass = (Class) fieldType;
    } else if (fieldType instanceof GenericArrayType) {
        if (isWriteTypeInfoGenericArray((GenericArrayType) fieldType, objectClass)) {
            return false;
        }
    } else if (fieldType instanceof ParameterizedType) {
        Type rawType = ((ParameterizedType) fieldType).getRawType();
        if (rawType instanceof Class) {
            fieldClass = (Class) rawType;
        }
    }
    if (objectClass == fieldClass) {
        return false;
    }

    if ((features & NotWriteHashMapArrayListClassName.mask) != 0) {
        if (objectClass == HashMap.class || objectClass == ArrayList.class) {
            return false;
        }
    }

    return (features & NotWriteRootClassName.mask) == 0
            || object != this.rootObject;
}

public final boolean isWriteTypeInfo(Object object, Type fieldType, long features) {
    features |= context.features;

    if ((features & WriteClassName.mask) == 0) {
        return false;
    }

    if (object == null) {
        return false;
    }

    Class objectClass = object.getClass();
    Class fieldClass = null;
    if (fieldType instanceof Class) {
        fieldClass = (Class) fieldType;
    } else if (fieldType instanceof ParameterizedType) {
        Type rawType = ((ParameterizedType) fieldType).getRawType();
        if (rawType instanceof Class) {
            fieldClass = (Class) rawType;
        }
    }
    if (objectClass == fieldClass) {
        return false;
    }

    if ((features & NotWriteHashMapArrayListClassName.mask) != 0) {
        if (objectClass == HashMap.class) {
            if (fieldClass == null || fieldClass == Object.class || fieldClass == Map.class || fieldClass == AbstractMap.class) {
                return false;
            }
        } else if (objectClass == ArrayList.class) {
            return false;
        }
    }

    return (features & NotWriteRootClassName.mask) == 0
            || object != this.rootObject;
}
